INSERT INTO `v1_75adac945e8f16dfa28b2a3e88f9bea5ec2d76a718e94d9a839af11a65ca15bb` VALUES ("2024/10/31 12:00:00", 130011, 3001100, 1, 2, 100, "ミッションねえ……\nちょうどいいや\nどこまで片付けられるか\n賭けをしようじゃないか", 2.1, "ヤマト", 3001, 0.0, -416.5, "2030/01/01 14:59:59");
INSERT INTO `v1_75adac945e8f16dfa28b2a3e88f9bea5ec2d76a718e94d9a839af11a65ca15bb` VALUES ("2024/10/31 12:00:00", 130011, 3001101, 4, 2, 101, "他人から言われた任務を\n言われるままにやるなんざ\n性に合わないんだがね……\nま、報酬は貰っとこうか", 5.68, "ヤマト", 3001, 0.0, -416.5, "2030/01/01 14:59:59");
INSERT INTO `v1_75adac945e8f16dfa28b2a3e88f9bea5ec2d76a718e94d9a839af11a65ca15bb` VALUES ("2024/10/31 12:00:00", 130011, 3001102, 1, 1, 102, "なんだい？　やれンなら\nとっとと済ませちまいな。\nフブキが早くやることやれ\nってボヤいてたよ。", 0.0, "ヤマト", 3001, 0.0, -416.5, "2030/01/01 14:59:59");
INSERT INTO `v1_75adac945e8f16dfa28b2a3e88f9bea5ec2d76a718e94d9a839af11a65ca15bb` VALUES ("2024/10/31 12:00:00", 130211, 3002100, 1, 1, 100, "え～？　ぼくに頼みごと～？\nどうしちゃおっかな～\nちゃんとお願いできたら\n考えてあげよっかな～？", 0.0, "フブキ", 3002, 0.0, -416.5, "2030/01/01 14:59:59");
INSERT INTO `v1_75adac945e8f16dfa28b2a3e88f9bea5ec2d76a718e94d9a839af11a65ca15bb` VALUES ("2024/10/31 12:00:00", 130211, 3002101, 1, 1, 101, "ほらほらぁ、これが\n欲しいんでしょ～？\nほんと、しょうがないよね～\nザコおに～いさん♡", 0.0, "フブキ", 3002, 0.0, -416.5, "2030/01/01 14:59:59");
INSERT INTO `v1_75adac945e8f16dfa28b2a3e88f9bea5ec2d76a718e94d9a839af11a65ca15bb` VALUES ("2024/10/31 12:00:00", 130211, 3002102, 5, 2, 102, "へえ～、欲しいんだ～？\nぼくのた・い・せ・つ・な・モ・ノ\nあははっ！　なに考えてんの？\nもうへんふしじゃ～んｗ", 8.53, "フブキ", 3002, 0.0, -416.5, "2030/01/01 14:59:59");
INSERT INTO `v1_75adac945e8f16dfa28b2a3e88f9bea5ec2d76a718e94d9a839af11a65ca15bb` VALUES ("2024/10/31 12:00:00", 130211, 3002103, 7, 1, 103, "なになに～？　もしかしてまた\nおねだりするつもりなんだ？\nとか言って、ほんとはぼくに\n会いたいだけだったりして～？", 5.67, "フブキ", 3002, 0.0, -416.5, "2030/01/01 14:59:59");
INSERT INTO `v1_75adac945e8f16dfa28b2a3e88f9bea5ec2d76a718e94d9a839af11a65ca15bb` VALUES ("2024/10/31 12:00:00", 130211, 3002104, 1, 1, 104, "ザコお兄さんってぇ\n頼み方もワンパなのぉ～？\nもっと必死にならないと\nぼくの心は動かせないよ～？", 0.0, "フブキ", 3002, 0.0, -416.5, "2030/01/01 14:59:59");
INSERT INTO `v1_75adac945e8f16dfa28b2a3e88f9bea5ec2d76a718e94d9a839af11a65ca15bb` VALUES ("2024/10/31 12:00:00", 130211, 3002300, 3, 3, 300, "あのさーザコお兄さん、\nな～んか調子乗ってない？\nぼくのこと、なんでもくれる\nチョロいやつとか思ってたりー？", 0.0, "フブキ", 3004, 0.0, -416.5, "2030/01/01 14:59:59");
INSERT INTO `v1_75adac945e8f16dfa28b2a3e88f9bea5ec2d76a718e94d9a839af11a65ca15bb` VALUES ("2024/10/31 12:00:00", 130211, 3002400, 7, 7, 301, "ざんね～ん♪\nうざいお兄さんには、もうな～んにもあげませ～ん♡\nほんとなっさけなーい♪\nばいば～い♡", 0.0, "フブキ", 3005, 0.0, -416.5, "2030/01/01 14:59:59");
INSERT INTO `v1_75adac945e8f16dfa28b2a3e88f9bea5ec2d76a718e94d9a839af11a65ca15bb` VALUES ("2024/10/31 12:00:00", 130211, 3003200, 2, 1, 200, "きゃはは、ほんと必死～♡\nは～、面白かった。\n笑えたからいいよ～\nそれ、恵んだげる～♪", 4.4, "フブキ", 3003, 0.0, -416.5, "2030/01/01 14:59:59");
INSERT INTO `v1_75adac945e8f16dfa28b2a3e88f9bea5ec2d76a718e94d9a839af11a65ca15bb` VALUES ("2024/10/31 12:00:00", 130211, 3003201, 7, 7, 201, "は～、しょうがないな～♡\nザコお兄さんってば\nほんとよわよわで\n情けないよね～ｗ", 0.0, "フブキ", 3003, 0.0, -416.5, "2030/01/01 14:59:59");
INSERT INTO `v1_75adac945e8f16dfa28b2a3e88f9bea5ec2d76a718e94d9a839af11a65ca15bb` VALUES ("2024/10/31 12:00:00", 130211, 3003202, 1, 2, 202, "お兄さんってば、ぼくがいないと\nほんとザッコザコだよね～\nもっと感謝しろし～♪", 5.6, "フブキ", 3003, 0.0, -416.5, "2030/01/01 14:59:59");
